	ep := mgr.lookupCNIAttachmentID(id)
	mgr.mutex.RUnlock()
	return ep
}

// LookupIPv4 looks up endpoint by IPv4 address
func (mgr *endpointManager) LookupIPv4(ipv4 string) *endpoint.Endpoint {
